mapper.select:


    i.del_flag = '0'
    and i.task_id = #{taskId}
    and i.workpiece_name like concat('%', #{workpieceName}, '%')
    and i.customer_dept_id = #{customerDeptId}
    and i.study_instance_uid like concat('%', #{studyInstanceUid}, '%')
    and i.series_instance_uid like concat('%', #{seriesInstanceUid}, '%')
    and i.sop_instance_uid like concat('%', #{sopInstanceUid}, '%')
    and i.modality = #{modality}
    and i.integrity_status = #{integrityStatus}

        and exists (
            select 1 from ndt_task_user tu
             where tu.task_id = i.task_id and tu.user_id = #{params.scopeUserId} and tu.can_view = '1'
        )

    and i.customer_dept_id = #{params.scopeDeptId}
    and 1 = 0

order by i.upload_time desc, i.id desc
